sys_ws_operation.operation_script:
(function process(/*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {
    var result = {
        status: "success",
        incident_mandatory_fields: []
    };

    try {
        var labels = [];
        if (request.queryParams.label) {
            for (var k = 0; k < request.queryParams.label.length; k++) {
                var trimmed = String(request.queryParams.label[k]).trim();
                if (trimmed) labels.push(trimmed);
            }
        }

        var lowerLabels = [];
        for (var k = 0; k < labels.length; k++) {
            lowerLabels.push(labels[k].toLowerCase());
        }

        var limit = 100;
        var addedFields = {};
        var allFields = [];

        var tables = ['task', 'incident'];
        for (var i = 0; i < tables.length; i++) {
            var dictGR = new GlideRecord('sys_dictionary');
            dictGR.addQuery('name', tables[i]);
            dictGR.addQuery('internal_type', '!=', 'collection');
            dictGR.orderBy('column_label');
            dictGR.query();

            while (dictGR.next()) {
                var fieldName = dictGR.element.toString();
                if (addedFields[fieldName]) continue;

                var fieldLabel = dictGR.column_label.toString();

                // Filter: field label must contain at least one of the labels
                if (lowerLabels.length > 0) {
                    var fieldLabelLower = fieldLabel.toLowerCase();
                    var matched = false;
                    for (var m = 0; m < lowerLabels.length; m++) {
                        if (fieldLabelLower.indexOf(lowerLabels[m]) !== -1) {
                            matched = true;
                            break;
                        }
                    }
                    if (!matched) continue;
                }

                allFields.push({
                    label: fieldLabel,
                    name: fieldName,
                });
                addedFields[fieldName] = true;
            }
        }

        // Sort by relevance if labels provided
        if (lowerLabels.length > 0) {
            allFields.sort(function(a, b) {
                var aLower = a.label.toLowerCase();
                var bLower = b.label.toLowerCase();

                // Tier 0: Exact match with any label
                var aExact = 1, bExact = 1;
                for (var x = 0; x < lowerLabels.length; x++) {
                    if (aLower === lowerLabels[x]) { aExact = 0; break; }
                }
                for (var x = 0; x < lowerLabels.length; x++) {
                    if (bLower === lowerLabels[x]) { bExact = 0; break; }
                }
                if (aExact !== bExact) return aExact - bExact;

                // Tier 1: Starts with any label
                var aStarts = 1, bStarts = 1;
                for (var x = 0; x < lowerLabels.length; x++) {
                    if (aLower.indexOf(lowerLabels[x]) === 0) { aStarts = 0; break; }
                }
                for (var x = 0; x < lowerLabels.length; x++) {
                    if (bLower.indexOf(lowerLabels[x]) === 0) { bStarts = 0; break; }
                }
                if (aStarts !== bStarts) return aStarts - bStarts;

                // Tier 2: Alphabetical
                return aLower < bLower ? -1 : (aLower > bLower ? 1 : 0);
            });
        }

        result.incident_mandatory_fields = allFields.slice(0, limit);

        response.setStatus(200);
        return result;

    } catch (e) {
        response.setStatus(400);
        return {
            status: "error",
            message: e.message || "Unexpected error occurred while processing the request."
        };
    }

})(request, response);
